"use client"

import { AdminLayout } from "@/components/admin-layout"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { mockDeals } from "@/lib/mock-data"
import { Trash2, Edit2, Plus } from "lucide-react"
import { useState } from "react"
import Link from "next/link"

interface Deal {
  id: string
  address: string
  price: number
  arv: number
  profitPercent: number
  status: "PASS" | "FAIL"
}

export default function DealsPage() {
  const [filter, setFilter] = useState<"ALL" | "PASS" | "FAIL">("ALL")
  const [deals, setDeals] = useState<Deal[]>(mockDeals)
  const [isCreating, setIsCreating] = useState(false)
  const [editingId, setEditingId] = useState<string | null>(null)
  const [formData, setFormData] = useState({
    address: "",
    price: 0,
    arv: 0,
    profitPercent: 0,
    status: "PASS" as const,
  })

  const filteredDeals = deals.filter((deal) => {
    if (filter === "ALL") return true
    return deal.status === filter
  })

  const handleCreate = () => {
    if (!formData.address || formData.price <= 0) return

    const newDeal: Deal = {
      id: Date.now().toString(),
      ...formData,
    }

    setDeals([...deals, newDeal])
    setFormData({ address: "", price: 0, arv: 0, profitPercent: 0, status: "PASS" })
    setIsCreating(false)
  }

  const handleUpdate = () => {
    if (!editingId || !formData.address || formData.price <= 0) return

    setDeals(deals.map((deal) => (deal.id === editingId ? { ...deal, ...formData } : deal)))
    setEditingId(null)
    setFormData({ address: "", price: 0, arv: 0, profitPercent: 0, status: "PASS" })
  }

  const handleDelete = (id: string) => {
    setDeals(deals.filter((deal) => deal.id !== id))
  }

  const handleEdit = (deal: Deal) => {
    setEditingId(deal.id)
    setFormData({
      address: deal.address,
      price: deal.price,
      arv: deal.arv,
      profitPercent: deal.profitPercent,
      status: deal.status,
    })
  }

  return (
    <AdminLayout>
      <div className="p-8 space-y-6">
        <div className="flex items-center justify-between">
          <div className="space-y-2">
            <h1 className="text-4xl font-bold text-foreground">Deals Management</h1>
            <p className="text-muted-foreground">Create, edit, and analyze properties</p>
          </div>
          <Button
            onClick={() => {
              setIsCreating(!isCreating)
              setEditingId(null)
              setFormData({ address: "", price: 0, arv: 0, profitPercent: 0, status: "PASS" })
            }}
            className="gap-2 bg-primary hover:bg-primary/90"
          >
            <Plus className="w-4 h-4" />
            New Deal
          </Button>
        </div>

        {(isCreating || editingId) && (
          <Card className="border-primary/30 bg-primary/5">
            <CardHeader>
              <CardTitle>{editingId ? "Edit Deal" : "Create New Deal"}</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="address" className="text-foreground font-medium">
                    Address
                  </Label>
                  <Input
                    id="address"
                    value={formData.address}
                    onChange={(e) => setFormData({ ...formData, address: e.target.value })}
                    placeholder="123 Main St"
                    className="bg-background"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="price" className="text-foreground font-medium">
                    Purchase Price
                  </Label>
                  <Input
                    id="price"
                    type="number"
                    value={formData.price || ""}
                    onChange={(e) => setFormData({ ...formData, price: Number.parseFloat(e.target.value) })}
                    placeholder="0"
                    className="bg-background"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="arv" className="text-foreground font-medium">
                    ARV
                  </Label>
                  <Input
                    id="arv"
                    type="number"
                    value={formData.arv || ""}
                    onChange={(e) => setFormData({ ...formData, arv: Number.parseFloat(e.target.value) })}
                    placeholder="0"
                    className="bg-background"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="profit" className="text-foreground font-medium">
                    Profit %
                  </Label>
                  <Input
                    id="profit"
                    type="number"
                    value={formData.profitPercent || ""}
                    onChange={(e) => setFormData({ ...formData, profitPercent: Number.parseFloat(e.target.value) })}
                    placeholder="0"
                    className="bg-background"
                  />
                </div>
              </div>
              <div className="space-y-2">
                <Label htmlFor="status" className="text-foreground font-medium">
                  Status
                </Label>
                <select
                  id="status"
                  value={formData.status}
                  onChange={(e) => setFormData({ ...formData, status: e.target.value as "PASS" | "FAIL" })}
                  className="w-full px-3 py-2 rounded-lg border border-border bg-background text-foreground"
                >
                  <option value="PASS">Pass</option>
                  <option value="FAIL">Fail</option>
                </select>
              </div>
              <div className="flex gap-2 justify-end">
                <Button
                  variant="outline"
                  onClick={() => {
                    setIsCreating(false)
                    setEditingId(null)
                    setFormData({ address: "", price: 0, arv: 0, profitPercent: 0, status: "PASS" })
                  }}
                >
                  Cancel
                </Button>
                <Button onClick={editingId ? handleUpdate : handleCreate} className="bg-primary hover:bg-primary/90">
                  {editingId ? "Update" : "Create"}
                </Button>
              </div>
            </CardContent>
          </Card>
        )}

        <div className="flex items-center gap-2">
          {(["ALL", "PASS", "FAIL"] as const).map((status) => (
            <Button
              key={status}
              variant={filter === status ? "default" : "outline"}
              onClick={() => setFilter(status)}
              size="sm"
            >
              {status === "ALL" ? "All" : status} ({filteredDeals.length})
            </Button>
          ))}
        </div>

        <Card>
          <CardHeader>
            <CardTitle>Properties</CardTitle>
            <CardDescription>Complete list of analyzed deals ({filteredDeals.length})</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-border">
                    <th className="text-left py-3 px-4 font-semibold text-sm text-muted-foreground">Address</th>
                    <th className="text-right py-3 px-4 font-semibold text-sm text-muted-foreground">Price</th>
                    <th className="text-right py-3 px-4 font-semibold text-sm text-muted-foreground">ARV</th>
                    <th className="text-right py-3 px-4 font-semibold text-sm text-muted-foreground">Profit %</th>
                    <th className="text-center py-3 px-4 font-semibold text-sm text-muted-foreground">Status</th>
                    <th className="text-center py-3 px-4 font-semibold text-sm text-muted-foreground">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredDeals.map((deal) => (
                    <tr key={deal.id} className="border-b border-border hover:bg-muted/50 transition-colors">
                      <td className="py-3 px-4 text-sm">{deal.address}</td>
                      <td className="text-right py-3 px-4 text-sm">${deal.price.toLocaleString()}</td>
                      <td className="text-right py-3 px-4 text-sm">${deal.arv.toLocaleString()}</td>
                      <td
                        className={`text-right py-3 px-4 text-sm font-medium ${deal.profitPercent >= 0 ? "text-success" : "text-destructive"}`}
                      >
                        {deal.profitPercent}%
                      </td>
                      <td className="text-center py-3 px-4">
                        <span
                          className={`inline-block px-3 py-1 rounded-full text-xs font-semibold ${
                            deal.status === "PASS" ? "bg-success/20 text-success" : "bg-destructive/20 text-destructive"
                          }`}
                        >
                          {deal.status}
                        </span>
                      </td>
                      <td className="text-center py-3 px-4">
                        <div className="flex justify-center gap-2">
                          <button
                            onClick={() => handleEdit(deal)}
                            className="text-primary hover:text-primary/80 transition-colors"
                            title="Edit"
                          >
                            <Edit2 className="w-4 h-4" />
                          </button>
                          <button
                            onClick={() => handleDelete(deal.id)}
                            className="text-destructive hover:text-destructive/80 transition-colors"
                            title="Delete"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                          <Link href={`/deals/${deal.id}`}>
                            <button className="text-accent hover:text-accent/80 transition-colors text-sm font-medium">
                              View
                            </button>
                          </Link>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </CardContent>
        </Card>
      </div>
    </AdminLayout>
  )
}
